def is_multiply_prime(a):
    if a < 2:
        return False

    primes = []
    n = a
    d = 2
    while d * d <= n:
        while n % d == 0:
            primes.append(d)
            n //= d
        d += 1
    if n > 1:
        primes.append(n)

    return len(primes) == 3 and all(p > 1 for p in primes)
