def encrypt(s):
    result = ""
    for char in s:
        if char.isalpha():
            shift = 2 * 2
            if char.islower():
                encrypted_char = chr((ord(char) - ord('a') + shift) % 26 + ord('a'))
            else:
                encrypted_char = chr((ord(char) - ord('A') + shift) % 26 + ord('A'))
            result += encrypted_char
        else:
            result += char
    return result
```

