def solve(s):
    letters = [c for c in s if c.isalpha()]
    if not letters:
        return s[::-1]
    result = []
    for char in s:
        if char.isalpha():
            if char.islower():
                result.append(char.upper())
            else:
                result.append(char.lower())
        else:
            result.append(char)
    return ''.join(result)
